import type { DatasetType } from "../types/sync.js";

export interface DatasetSource {
    /** Stable unique id generated by the store implementation. */
    id: string;
    type: DatasetType;
    name: string;
    disabled?: boolean;
    description?: string;
    baseUrl?: string;
    apiKey?: string;
    lastSnapshotSync?: string;
    lastUpdateSync?: string;
}

export interface DatasetSourceStore {
    listByType: (type: DatasetType) => Promise<DatasetSource[]>;
    read: (id: string) => Promise<DatasetSource | undefined>;
    /**
     * Create a dataset source. The store generates the unique id.
     * Callers may optionally provide an id (ignored by the file store).
     */
    create: (create: Omit<DatasetSource, "id"> & { id?: string }) => Promise<DatasetSource>;
    update: (update: DatasetSource) => Promise<DatasetSource>;
    delete: (id: string) => Promise<void>;
}
